  /*
+  * Hook for drivers to report dropped packets
+  */
+ void
+ bpf_dropcnt(ifp, drop)
+ 	struct ifnet *ifp;
+ 	u_int drop;
+ {
+ 	struct bpf_if *bp = ifp->if_bpf;
+ 	struct bpf_d *d;
+ 
+ 	for (d = bp->bif_dlist; d != NULL; d = d->bd_next)
+ 		d->bd_dcount += drop;
+ }
